import { isSupportPerformanceObserver } from './utils'
import { onBFCacheRestore, getPageURL } from '../utils/utils'
import { lazyReportCache } from '../utils/report'

export default function observePaint() {
    if (!isSupportPerformanceObserver()) return
    
    const entryHandler = (list) => {        
        const entries = list.getEntries()
        for (const entry of entries) {
            const json = entry.toJSON()
            delete json.duration
    
            const reportData = {
                ...json,
                subType: entry.name,
                type: 'performance',
                pageURL: getPageURL(),
            }

            lazyReportCache(reportData)
        }
        
        // 检查是否已经获取到了所有的 paint 条目
        const paintEntryNames = entries.map(entry => entry.name)
        if (paintEntryNames.includes('first-paint') && paintEntryNames.includes('first-contentful-paint')) {
            observer.disconnect()
        }
    }
    
    const observer = new PerformanceObserver(entryHandler)
    observer.observe({ type: 'paint', buffered: true })

    onBFCacheRestore(event => {
        requestAnimationFrame(() => {
            ['first-paint', 'first-contentful-paint'].forEach(type => {
                lazyReportCache({
                    startTime: performance.now() - event.timeStamp,
                    name: type,
                    subType: type,
                    type: 'performance',
                    pageURL: getPageURL(),
                    bfc: true,
                })
            })
        })
    })
}