import error from './error/index'
import performance from './performance/index'
import behavior from './behavior/index'
import { setConfig, updateConfig } from './config'
import { onBeforeunload, onHidden, onVisibilityChange, getFingerprint as getFp, getSessionId as getSid } from './utils/utils'
import { report as originalReport } from './utils/report'
import { getCache, clearCache } from './utils/cache'
import config from './config'

// 安全执行函数，捕获并处理异常
function safeExecute(fn, ...args) {
    try {
        return fn(...args)
    } catch (error) {
        console.warn('SDK 内部错误:', error)
        // 可以在这里添加错误上报逻辑
        return null
    }
}

// 包装 report 方法，确保上报过程中的错误不会影响业务页面
const safeReport = (...args) => {
    return safeExecute(originalReport, ...args)
}

// 页面可见性变化处理
function handleVisibilityChange() {
    const pageState = {
        isHidden: document.hidden,
        timestamp: Date.now(),
        duration: 0
    }

    let lastVisibleTime = Date.now()

    onVisibilityChange(() => {
        if (document.hidden) {
            // 页面进入后台
            pageState.isHidden = true
            pageState.timestamp = Date.now()
            lastVisibleTime = Date.now()

            // 上报页面进入后台事件
            safeExecute(() => {
                safeReport({
                    type: 'behavior',
                    subType: 'page-visibility',
                    action: 'hide',
                    timestamp: pageState.timestamp
                })
            })
        } else {
            // 页面回到前台
            const currentTime = Date.now()
            pageState.isHidden = false
            pageState.duration = currentTime - lastVisibleTime
            pageState.timestamp = currentTime

            // 上报页面回到前台事件
            safeExecute(() => {
                safeReport({
                    type: 'behavior',
                    subType: 'page-visibility',
                    action: 'show',
                    timestamp: pageState.timestamp,
                    duration: pageState.duration
                })
            })
        }
    })
}

const monitor = {
    init(options = {}) {
        safeExecute(() => {
            setConfig(options)

            // 根据配置开关决定是否启用相应功能
            if (config.enableError) {
                safeExecute(error)
            }

            if (config.enablePerformance) {
                safeExecute(performance)
            }

            if (config.enableBehavior) {
                safeExecute(behavior)
                // 初始化页面可见性变化监控
                safeExecute(handleVisibilityChange)
            }

            // 当页面进入后台或关闭前时，将所有的 cache 数据进行上报
            [onBeforeunload, onHidden].forEach(fn => {
                fn(() => {
                    safeExecute(() => {
                        const data = getCache()
                        if (data.length) {
                            safeReport(data, true)
                            clearCache()
                        }
                    })
                })
            })
        })
    },
    report: safeReport,
    // 动态配置开关
    setConfig(options) {
        safeExecute(() => {
            updateConfig(options)
        })
    },
    // 获取用户唯一标识
    getFingerprint() {
        const fp = getFingerprint
        return safeExecute(fp)
    },
    // 获取会话 ID
    getSessionId() {
        const sid = getSessionId
        return safeExecute(sid)
    },
    // 用于测试 SDK 异常隔离功能的方法
    testCrash() {
        throw new Error('SDK 测试崩溃')
    }
}

export default monitor