import { isSupportPerformanceObserver } from './utils'
import { executeAfterLoad } from '../utils/utils'
import { lazyReportCache } from '../utils/report'

export default function observeEntries() {
    executeAfterLoad(() => {
        observeEvent('resource')
        observeEvent('navigation')
        observeEvent('longtask')
    })
}

let hasAlreadyCollected = false
export function observeEvent(entryType) {
    function entryHandler(list) {
        const data = list.getEntries ? list.getEntries() : list
        for (const entry of data) {
            if (entryType === 'navigation') {
                if (hasAlreadyCollected) return

                if (observer) {
                    observer.disconnect()
                }

                hasAlreadyCollected = true
            }
            
            // 处理长任务
            if (entryType === 'longtask') {
                lazyReportCache({
                    name: entry.name,
                    subType: entryType,
                    type: 'performance',
                    duration: entry.duration, // 长任务持续时间
                    startTime: entry.startTime, // 长任务开始时间
                    attribution: entry.attribution ? JSON.stringify(entry.attribution) : null, // 任务归因
                })
                continue
            }
            
            // nextHopProtocol 属性为空，说明资源解析错误或者跨域
            // beacon 用于上报数据，所以不统计。xhr fetch 单独统计
            if ((!entry.nextHopProtocol && entryType !== 'navigation') || filter(entry.initiatorType)) {
                return
            }

            // 详细的资源加载各阶段耗时分析
            const resourceDetails = {
                name: entry.name, // 资源名称
                subType: entryType,
                type: 'performance',
                sourceType: entry.initiatorType, // 资源类型
                resourceType: getResourceType(entry.name), // 资源具体类型（图片、JS、CSS等）
                duration: entry.duration, // 资源加载总耗时
                dns: entry.domainLookupEnd - entry.domainLookupStart, // DNS 解析耗时
                tcp: entry.connectEnd - entry.connectStart, // TCP 连接耗时
                ssl: entry.secureConnectionStart ? (entry.connectEnd - entry.secureConnectionStart) : 0, // SSL 握手耗时
                redirect: entry.redirectEnd - entry.redirectStart, // 重定向耗时
                ttfb: entry.responseStart, // 首字节时间
                download: entry.responseEnd - entry.responseStart, // 内容下载耗时
                processing: entry.duration - (entry.responseEnd - entry.startTime), // 资源处理耗时
                protocol: entry.nextHopProtocol, // 请求协议
                responseBodySize: entry.encodedBodySize, // 响应内容大小
                responseHeaderSize: entry.transferSize - entry.encodedBodySize, // 响应头部大小
                resourceSize: entry.decodedBodySize, // 资源解压后的大小
                isCache: isCache(entry), // 是否命中缓存
                startTime: entry.startTime, // 资源开始加载时间
                endTime: entry.responseEnd, // 资源加载完成时间
                timestamp: performance.now(), // 上报时间戳
            }

            lazyReportCache(resourceDetails)
        }
    }

    let observer
    if (isSupportPerformanceObserver()) {
        observer = new PerformanceObserver(entryHandler)
        observer.observe({ type: entryType, buffered: true })
    } else {
        const data = window.performance.getEntriesByType(entryType)
        entryHandler(data)
    }
}

// 不统计以下类型的资源
const preventType = ['fetch', 'xmlhttprequest', 'beacon']
const isSafari = /Safari/.test(navigator.userAgent) && !/Chrome/.test(navigator.userAgent)
if (isSafari) {
    // safari 会把接口请求当成 other
    preventType.push('other')
}

function filter(type) {
    return preventType.includes(type)
}

function isCache(entry) {
    // 直接从缓存读取或 304
    return entry.transferSize === 0 || (entry.transferSize !== 0 && entry.encodedBodySize === 0)
}

// 根据资源 URL 判断资源类型
function getResourceType(url) {
    const lowerUrl = url.toLowerCase()
    if (lowerUrl.endsWith('.js') || lowerUrl.includes('.js?')) {
        return 'script'
    } else if (lowerUrl.endsWith('.css') || lowerUrl.includes('.css?')) {
        return 'stylesheet'
    } else if (lowerUrl.match(/\.(jpg|jpeg|png|gif|webp|svg|bmp)$/i)) {
        return 'image'
    } else if (lowerUrl.match(/\.(woff|woff2|ttf|otf|eot)$/i)) {
        return 'font'
    } else if (lowerUrl.endsWith('.html') || lowerUrl.endsWith('.htm')) {
        return 'document'
    } else if (lowerUrl.endsWith('.json') || lowerUrl.includes('.json?')) {
        return 'json'
    } else {
        return 'other'
    }
}